    zinc: 'bg-white/5 text-zinc-400 border-white/10 hover:bg-white hover:text-black',
  };

  return (
    <div className="relative group/tooltip">
      <button 
        onClick={onClick}
        className={`p-2 rounded-lg border transition-all ${colors[color]}`}
      >
        <Icon className="w-4 h-4" />
