  entropy: number;
  crackTime: { seconds: number; label: string };
  charsetSize: number;
  length: number;
  patterns: string[];
  suggestions: string[];
  hasUppercase: boolean;
  hasLowercase: boolean;
  hasNumbers: boolean;
  hasSymbols: boolean;
  protocols: { name: string; status: string; detail: string }[];
