      if (password) {
        analyzePassword(password);
      } else {
        setResult(null);
      }
    }, 500);

    return () => clearTimeout(delayDebounceFn);
  }, [password]);

  const analyzePassword = async (pwd: string) => {
    setIsAnalyzing(true);
    try {
      const res = await apiFetch('/analyze', {
        method: 'POST',
        body: JSON.stringify({ password: pwd })
      });
      const data = await res.json();
