                    }`}>
                      {result.pwnedCount > 0 ? <ShieldAlert className="w-8 h-8" /> : <ShieldCheck className="w-8 h-8" />}
                    </div>
                    <div>
                      <h2 className={`text-2xl font-black ${result.pwnedCount > 0 ? 'text-red-400' : 'text-emerald-400'}`}>
