                   </div>
                </div>
              </div>
              <div className="lg:col-span-4">
                <div className="bg-blue-600 rounded-[3rem] p-8 shadow-2xl relative overflow-hidden">
                  <Fingerprint className="w-12 h-12 text-white/30 mb-6" />
