          )}
        </motion.div>
      </div>
    );
  }

  // ── RENDER: RECOVERY FLOW ──────────────────────────────────────────────────
  if (isRecoveryMode) {
    return (
      <div className="max-w-md mx-auto mt-20 p-4">
        <motion.div 
