"use client";

import * as React from "react";
import { useTheme } from "next-themes";
import { Sun, Moon, Monitor } from "lucide-react";
import { motion } from "framer-motion";

export function ThemeToggle() {
  const { theme, setTheme } = useTheme();
  const [mounted, setMounted] = React.useState(false);

  React.useEffect(() => {
    setMounted(true);
  }, []);

  if (!mounted) {
    return <div className="w-[104px] h-[36px] bg-black/40 border border-white/5 rounded-xl" />;
  }

  return (
    <div className="flex items-center gap-1 bg-black/40 border border-white/10 p-1 rounded-xl backdrop-blur-md">
      <button
        onClick={() => setTheme("light")}
        className={`relative p-1.5 rounded-lg text-xs font-bold transition-all z-10 ${
          theme === "light" ? "text-primary" : "text-zinc-500 hover:text-zinc-300"
        }`}
        title="Light Mode"
      >
        <Sun className="w-4 h-4" />
        {theme === "light" && (
          <motion.div
            layoutId="theme-active"
            className="absolute inset-0 bg-primary/10 border border-primary/20 rounded-lg -z-10"
            transition={{ type: "spring", bounce: 0.2, duration: 0.6 }}
          />
        )}
      </button>

      <button
        onClick={() => setTheme("dark")}
        className={`relative p-1.5 rounded-lg text-xs font-bold transition-all z-10 ${
          theme === "dark" ? "text-primary" : "text-zinc-500 hover:text-zinc-300"
        }`}
        title="Dark Mode"
      >
        <Moon className="w-4 h-4" />
        {theme === "dark" && (
          <motion.div
            layoutId="theme-active"
            className="absolute inset-0 bg-primary/10 border border-primary/20 rounded-lg -z-10"
            transition={{ type: "spring", bounce: 0.2, duration: 0.6 }}
          />
        )}
      </button>

      <button
        onClick={() => setTheme("system")}
        className={`relative p-1.5 rounded-lg text-xs font-bold transition-all z-10 ${
          theme === "system" ? "text-primary" : "text-zinc-500 hover:text-zinc-300"
        }`}
        title="System Preference"
      >
        <Monitor className="w-4 h-4" />
        {theme === "system" && (
          <motion.div
            layoutId="theme-active"
            className="absolute inset-0 bg-primary/10 border border-primary/20 rounded-lg -z-10"
            transition={{ type: "spring", bounce: 0.2, duration: 0.6 }}
          />
        )}
      </button>
    </div>
  );
}

import { useAuthStore } from '../store/useAuthStore';

const BASE_URL = 'http://localhost:5000/api';

export async function apiFetch(endpoint: string, options: RequestInit = {}) {
  const { accessToken, setAccessToken, logout } = useAuthStore.getState();

  const headers: any = {
    ...(accessToken ? { 'Authorization': `Bearer ${accessToken}` } : {}),
    ...options.headers,
  };

  if (options.body && !(options.body instanceof FormData)) {
    headers['Content-Type'] = 'application/json';
  }

  const config: RequestInit = {
    ...options,
    headers,
    credentials: 'include',
  };

  let response = await fetch(`${BASE_URL}${endpoint}`, config);

  // If unauthorized (token expired), try to refresh
  if (response.status === 401 && !endpoint.includes('/auth/login')) {
    try {
      const refreshRes = await fetch(`${BASE_URL}/auth/refresh`, {
        method: 'POST',
        credentials: 'include',
      });

      if (refreshRes.ok) {
        const { accessToken: newAccessToken } = await refreshRes.json();
        setAccessToken(newAccessToken);

        // Retry the original request with the new token
        const newHeaders = {
          ...headers,
          'Authorization': `Bearer ${newAccessToken}`,
        };
        response = await fetch(`${BASE_URL}${endpoint}`, { ...config, headers: newHeaders });
      } else {
        // Refresh failed, logout user
        logout();
        window.location.href = '/login';
      }
    } catch (err) {
      logout();
      window.location.href = '/login';
    }
  }

  return response;
}

import { apiFetch } from './api';
import { db } from './db';

export async function syncVault() {
  try {
    const res = await apiFetch('/vault');
    if (res.ok) {
      const data = await res.json();
      await db.vault.clear();
      const items = data.items || [];
      if (items.length > 0) {
        await db.vault.bulkPut(items.map((item: any) => ({
          id: item.id,
          category: item.category,
          encryptedData: item.encryptedData,
          updatedAt: item.createdAt
        })));
      }
    }
  } catch (err) {
    console.error('Vault sync failed', err);
  }
}

export async function syncMedical() {
  try {
    const res = await apiFetch('/medical');
    if (res.ok) {
      const data = await res.json();
      await db.medical.clear();
      const records = data.records || [];
      if (records.length > 0) {
        await db.medical.bulkPut(records.map((record: any) => ({
          id: record.id,
          category: record.category,
          encryptedData: record.encryptedData,
          updatedAt: record.createdAt
        })));
      }
    }
  } catch (err) {
    console.error('Medical sync failed', err);
  }
}

export async function syncFiles() {
  try {
    const res = await apiFetch('/files');
    if (res.ok) {
      const data = await res.json();
      await db.files.clear();
      const files = data.files || [];
      if (files.length > 0) {
        await db.files.bulkPut(files.map((file: any) => ({
          id: file.id,
          fileName: file.fileName,
          category: file.category,
          mimeType: file.mimeType,
          fileSize: file.fileSize,
          updatedAt: file.createdAt
        })));
      }
    }
  } catch (err) {
    console.error('Files sync failed', err);
  }
}

export async function syncAll() {
  if (typeof window !== 'undefined' && navigator.onLine) {
    await Promise.all([syncVault(), syncMedical(), syncFiles()]);
    console.log('All data synchronized for offline use.');
  }
}

